#include<bits/stdc++.h>
using namespace std;
long long n,m,f[14][14][43010];
vector<pair<long long,long long>> p;
map<pair<long long,long long>,long long> mp;
void dfs(long long x,long long u,long long v,long long w)
{
    if(x==m+1)
    {
        if(w==0)
        {
            p.push_back({u,v});
            mp[{u,v}]=(long long)(p.size())-1;
        }
        return;
    }
    dfs(x+1,u,v,w);
    dfs(x+1,u|(1<<x),v,w+1);
    if(w)
    {
        dfs(x+1,u|(1<<x),v|(1<<x),w-1);
    }
}
long long now[21],nxt[21];
long long encode(long long col[])
{
    long long a=0,b=0;
    for(long long i=0;i<=m;i++)
    {
        a+=(col[i]!=0)*(1<<i);
        b+=(col[i]==2)*(1<<i);
    }
    return mp[{a,b}];
}
void decode(long long col[],long long x)
{
    long long a=p[x].first,b=p[x].second;
    for(long long i=0;i<=m;i++)
    {
        long long tmp=((a>>i)&1),tmp1=((b>>i)&1);
        if(tmp==1)
        {
            if(tmp1==0)
            {
                col[i]=1;
            }
            else
            {
                col[i]=2;
            }
        }
        else
        {
            col[i]=0;
        }
    }
}
void c()
{
    memcpy(nxt,now,sizeof(nxt));
}
int main()
{
    scanf("%lld%lld",&n,&m);
    long long ans=0;
    p.push_back({0,0});
    dfs(0,0,0,0);
    long long s=p.size()-1;
    f[0][0][1]=1;
    for(long long i=0;i<n;i++)
    {
        for(long long j=0;j<m;j++)
        {
            char ch;
            cin>>ch;
            if(ch=='.')
            {
                ans=f[i][j][mp[{(1<<j)|(1<<(j+1)),1<<(j+1)}]];
            }
            for(long long k=1;k<=s;k++)
            {
                decode(now,k);
                if(ch=='*')
                {
                    if(!now[j]&&!now[j+1])
                    {
                        f[i][j+1][k]+=f[i][j][k];
                    }
                    continue;
                }
                if(!now[j]&&!now[j+1])
                {
                    c();
                    nxt[j]=1;
                    nxt[j+1]=2;
                    f[i][j+1][encode(nxt)]+=f[i][j][k];
                    continue;
                }
                if((now[j]&&!now[j+1])||(!now[j]&&now[j+1]))
                {
                    f[i][j+1][k]+=f[i][j][k];
                    c();
                    swap(nxt[j],nxt[j+1]);
                    f[i][j+1][encode(nxt)]+=f[i][j][k];
                    continue;
                }
                if(now[j]==1&&now[j+1]==1)
                {
                    long long sum=0;
                    c();
                    for(long long l=j+2;;l++)
                    {
                        sum+=(long long)(now[l]==1)-(long long)(now[l]==2);
                        if(sum<0)
                        {
                            nxt[j]=nxt[j+1]=0;
                            nxt[l]=1;
                            f[i][j+1][encode(nxt)]+=f[i][j][k];
                            break;
                        }
                    }
                    continue;
                }
                if(now[j]==2&&now[j+1]==2)
                {
                    long long sum=0;
                    c();
                    for(long long l=j-1;;l--)
                    {
                        sum+=(long long)(now[l]==1)-(long long)(now[l]==2);
                        if(sum>0)
                        {
                            nxt[j]=nxt[j+1]=0;
                            nxt[l]=2;
                            f[i][j+1][encode(nxt)]+=f[i][j][k];
                            break;
                        }
                    }
                    continue;
                }
                if(now[j]==2&&now[j+1]==1)
                {
                    c();
                    nxt[j]=nxt[j+1]=0;
                    f[i][j+1][encode(nxt)]+=f[i][j][k];
                    continue;
                }
            }
        }
        for(long long k=1;k<=s;k++)
        {
            long long u=p[k].first,v=p[k].second;
            if(!(u&(1<<m)))
            {
                f[i+1][0][mp[{u<<1,v<<1}]]+=f[i][m][k];
            }
        }
    }
    printf("%lld",ans);
    return 0;
}
